@startuml
left to right direction
package "User" as User {
  class signUp {
    -id: int
    -firstName: string
    -lastName: string
    -userName: string
    -email: string
    -password: string
    +signUp(): void
  }
  class signIn {
    -userName: string
    -password: string
    +login(): void
    +getUserId(): int
  }
  class registerItem {
    -id: int
    -description: string
  }
  class planAction {
  }
  class Date {
    -year: int
    -month: int
    -day: int
    +Date(year: int, month: int, day: int)
    +getYear(): int
    +getMonth(): int
    +getDay(): int
    +setYear(year: int): void
    +setMonth(month: int): void
    +setDay(day: int): void
    +toString(): string
    +setDate(year: int, month: int, day: int)
  }
  class Time {
    -second: int
    -minute: int
    -hour: int
    +Time()
    +Time(second: int, minute: int, hour: int)
    +getHour(): int
    +getMinute(): int
    +getSecond(): int
    +setHour(year: int): void
    +setMinute(minute: int): void
    +setSecond(second: int): void
    +toString(): string
    +setTime(second: int, minute: int, hour: int)
    +nextSecond(): Time
  }
}

class User {
  -id: int
  -userName: string
  -password: string
  +login(): void
  +signUp(): int
}

